import{_ as p,o as a,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"赤蛮奇","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/赤蛮奇.md","filePath":"4.资源分区/1.血统与训练/5.通用类/赤蛮奇.md"}'),n={name:"4.资源分区/1.血统与训练/5.通用类/赤蛮奇.md"};function o(d,b,i,l,h,_){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"赤蛮奇",tabindex:"-1"},[t("赤蛮奇 "),r("a",{class:"header-anchor",href:"#赤蛮奇","aria-label":'Permalink to "赤蛮奇"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD:灵魂蓝调011")])])],-1),s('<h1 id="赤蛮奇-1" tabindex="-1">赤蛮奇 <a class="header-anchor" href="#赤蛮奇-1" aria-label="Permalink to &quot;赤蛮奇&quot;">​</a></h1><p>赤蛮奇<br> 秦時，南方有「落頭民」，其頭能飛。<br> ——《搜神记·第十二卷》<br> 赤蛮奇是辘轳首妖怪，但是是飞头类型还是伸长脖子类型的辘轳首并不确定，似乎都可以做到。所拥有的就是让头飞出去程度的能力。在东方project里住在柳之运河的岸边，与人鱼若鹭姬和狼女今泉影狼共同组成了草根妖怪网路。首次登场于东方辉针城，担任辉针城的二面Boss。</p><p>爱尔兰的辘轳首<br> 价格：D+1100<br> 在原名拉夫卡迪奥·赫恩的爱尔兰裔日本作家小泉八云的志怪作品《怪谈·辘轳首》记载中，这类飞头妖怪一般被分为两种：一种是‘头与身体分离’的妖怪，一种是‘脖子会伸长’的妖怪。「辘轳」是利用滑轮原理制成的、从井中汲水的用具；「首」在日语里也指脖子。「辘轳首」指的是这种妖怪的脖子伸缩自如，就像辘轳的绳子一样。</p><p>「抜け首」<br> 头与身体分离的辘轳首也叫做抜け首。这种妖怪被认为是辘轳首的原型，并且来自中国传说中的妖怪飞头蛮。小泉八云《怪谈·辘轳首》中的辘轳首，就属于这种妖怪。<br> 效果：<br> 你被攻击时视为不再拥有头部，但你仍然拥有可见的脑袋，在判定你是否为拥有头颅的单位时取劣。<br> 你不再能使用头盔类装备。<br> 你的头部不会被当作特殊部位进行攻击（注，眼睛仍然可被作为特殊部位攻击），当你头部被攻击击中时正常计算防御与伤害，且不会因为切掉脑袋而死掉。<br> 你的脑袋可以在你臂展范围内悬浮，同时也意味着头部会单独被位移效果（例如冲撞）影响。<br> 你的头部与你的距离不应超过你的敏感范围，若超出，你的身体视为进入无助状态。<br> 如果你拥有多个头颅，你需要将至少一颗头设定为你的头部。你可以在非战斗状态下更换你的头部（如果你有多个头颅的话）。</p><p>「人部·南方异物志」<br> 《南方異物志》云︰嶺南溪峒中，有飛頭蠻，項有赤痕。至夜以耳為翼，飛去食蟲物，將曉複還如故也。——《本草纲目·人部》<br> 你现在可以购买更多的头来攻击，甚至复活你自己。它们平时可以毫无痕迹地收纳在你身体内部，在你需要的时候可以以一个自由动作召出。你可以让你的头叼着小物件被收纳，大小不得超过头的大小，且在头被召出时同时出现。<br> 你的机运骰获得一点机运加值。</p><p>首符「辘轳首飞来」<br> 妖力全用来维持存在的小妖怪通常把自己的肉体当作攻击的手段。你现在可以把你相当锋利的头扔出去狠狠地撞击可恶的毛玉，或者别的叫你母暴龙什么的可恶家伙了。当然，得自己捡回来。<br> 你的头现在视为一个0L的投掷物，造成钝击伤害，拥有【法破】特性。<br> 攻击检定方式为力量/敏捷+运动+投掷+武技专业：头，射程为力量*5m+力量上的附加成功*10m</p><p>体符「弹幕力场」<br> 在幻想乡天天要被弹幕揍，小妖怪们必须进化出相应的防御手段。大玉砸人真的很痛。<br> 你现在拥有基于天生防御的【防能量】特性。</p><p>克里特的飞头蛮<br> 价格：C+1200<br> 嶺南溪洞中往往有飛頭者，故有飛頭獠子之號。頭將飛一日前，頸有痕匝，項如紅縷，妻子遂看守之。其人及夜狀如病，頭忽生翼，脫身而去，乃於岸泥尋蟹蚓之類食，將曉飛還，如夢覺，其腹實矣。 ——《酉阳杂俎·卷四·境异》<br> 中国传说中的妖怪。平时是人类的姿态，夜里头部会离开身体，用耳朵当作翅膀飞走，以虫为食，早上再回到身体上。鸟山石燕《画图百鬼夜行》中绘有「飛頭蛮」，不过头身是相连的。</p><p>首符「头颅马戏」<br> 辘轳首的头会在夜里睡觉的时候飞走。会自己飞回来的，放心啦。<br> 你的脑袋现在可以以你的移动速度进行普通飞行。也可带着身体进行飞行，此时移动速度减半。<br> 现在你投掷头颅的攻击方式获得【回力】特性。<br> 你可以自由指挥购买的其他脑袋消耗它们自己的动作以【头颅本身的力量/敏捷+运动+投掷+武技专业：头】的方式进行攻击，在攻击之后会自动回到你身边。你原本的脑袋还蛮脆弱的，小心点哦。</p><p>境异「酉阳杂俎」<br> 你不再需要呼吸与休息。你开启妖力池的变体（不获得基础用法），其关键属性为敏捷+决心。每经过一场影片，这个妖力池便+1上限。你掌握自然派系的C级派系造诣。<br> 早稻田的杜拉罕<br> 价格：B+2400<br> 爱尔兰传说中的无头亡灵，预示着死亡。也叫「无头骑士」。杜拉罕（杜拉尔罕）会在人死亡之前喊出他们的名字，用以宣告对方的灭亡。爱尔兰语中名叫“Gan Ceann”，字面意义就是「没有头」。头颅位于人体的顶端，容纳着人体最重要的器官：大脑，控制着人类的一切活动。凯尔特人很早以前就意识到了这一点，并巧妙地将头部与权力、地位等意义关联起来。他们相信头颅是灵魂的居所，是容纳知识、灵感与预言的宝座，象征着力量与神性，甚至具有抵抗魔鬼入侵的魔力，因此会将经过处理的真人头或者木雕石刻的假人头安放在神龛、门廊或者井边以祈求庇护和好运。说到早稻田，辘轳首的传说正式小泉八云再早稻田大学执教期间整理完成的。</p><p>飞头「Dullahan Night」<br> 没有任何路障可以阻碍无头骑士的前进，任何阻碍物当无头骑士经过时都会自行开启。无头骑士也不喜欢他们在办事的途中被窥视，他们会向胆敢那样做的人们身上倒一盆血（基本上暗示了他们马上会得到的死亡），或是用他们的鞭子抽出窥视者的眼珠。<br> 在每日的开始你可以选择任意一项非自然骰检定，令其获得8加骰与5点幸运加值，你必须宣言它的发生这个增益才能起效，这一效果会持续至你进行下一次长休息或是再次使用本能力。<br> 如果你不想被人发现你的身形将不能被观测到，你获得D级魔幻本质的反侦测等级。<br> 你掌握自然派系的B级派系造诣。</p><p>蜚语「戈尔韦郡の伝言」<br> 根据戈尔韦郡当地的传说，用黄金制成的人工制品会使得杜拉罕产生“不合理的”恐惧，哪怕只是一根金针，都可以将他们重新驱赶回黑暗之中。<br> 你获得2dr/黄金。只有黄金制品能打破你身上坚不可摧的防御，一定要小心。</p><p>柳树下的凯尔特神<br> 价格：A+4800<br> 凯尔特人认为，这些被斩首的敌人的灵魂最终会成为自己部落的一员，为自己的族群贡献力量。对于他们而言，这些头颅的意义早已超越了单纯的战利品。凯尔特人向头颅表示敬意——无论那是敌人的头颅，还是自己先祖的头颅，他们都会像崇拜偶像一般去对待。</p><p>化身「大神Crom Dubh」<br> Crom Dubh又被称作土丘之王，在凯尔特神话中他被描述为一位太阳神，同时也是一位丰饶之神。在很久以前，爱尔兰人就有向Crom Dubh献祭儿童以求丰收的习俗，而自Tighermas国王统治时期起，这一习俗由献祭儿童改为了血祭，仪式以斩首的形式进行。<br> 你的能量池不再被称为妖力池，而是被称为神力池。<br> 你掌握自然派系的A级派系造诣。<br> 你的身体化为神灵承受着各凯尔特地区的供奉，身体不再重要，只要你仍有一颗结构值尚未归零的非特殊头颅，则当你本体死亡后，你就能在任意一颗头颅所在的地方重塑你的身躯，重塑身躯需要7天时间，这期间你不能使用任何特殊能力，这是一个A级别、命运来源的复活效果。<br> 当你死亡，你的神力贯通并于特殊头颅上显灵。<br> 你的复活仪式第一次启动后自然与太阳的神力洗涤了你，而神的重生不容打扰，你从此视为拥有B级魔幻本质的反侦测等级。</p><p>黑驹「Cóiste-bodhar」<br> “一天夜里，一名农夫沿着朗德斯东与巴利康尼利之间的小路回家，行经无人之处，忽然听闻背后传来急促的马蹄声。农夫停下脚步，回头一瞧，只见一名无头的黑衣骑士正骑着黑色骏马向自己疾驰而来。“——戈尔韦郡民间传说<br> 你现在拥有一匹名为Cóiste-bodhar的黑马，一辆名叫Cóiste-bodhar的摩托车...她的外形由你决定。<br> 你可以以一个自由动作召唤或收回她。在非召唤状态下，她会为你带来480米的移速的增益，毕竟她并非是一个独立的个体。<br> 以及，是的，她可以飞。<br> 她的数据如下：<br> 体积：10<br> 载具类型：轻型载具<br> 结构值：66<br> 装甲：36<br> 速度：240米/轮<br> 加速度：80米<br> 最大速度：960米/轮<br> 载员：驾驶员1，乘客3名，总体积不超过20<br> 机动性：完美飞行<br> 特殊能力：<br> 以此载具进行冲撞行为时，造成24L钝击严重伤害，反射豁免。</p><p>---------------赤蛮奇专属技能树------------------<br> 首符「闭目射击」<br> 类型：攻击技<br> 价格：D+500<br> 派系：自然<br> 能量消耗：2<br> 成分：动作<br> 动作：自由<br> 射程：15米<br> 效果：单体<br> 持续：一轮<br> 你从你的眼中射出一束激光，直指对面的脑壳。<br> 选择一个你的头颅，对攻击范围内的敌对目标进行一次攻击检定，构成为敏捷+射击+目光+能量操控（专注），在此次攻击中你造成穿刺伤害，你的头视为一件5法强的法器。</p><p>眼光「地狱之光」<br> 类型：攻击技<br> 价格：A+0<br> 派系：自然<br> 能量消耗：14<br> 成分：动作<br> 动作：整轮<br> 射程：敏捷*10米<br> 效果：单体<br> 持续：一轮<br> 杜拉罕的眼睛昭示着人的死亡。赤蛮奇有九双眼睛所以带来九次死亡！<br> 选择任意数量的个头颅，每个头颅都可选择你攻击范围内的单个敌对目标做崇。<br> 你对攻击范围内头颅选择的敌对目标进行一次攻击检定，构成为敏捷+射击+目光+能量操控（专注），被这次攻击命中的单位会立即死去，这是A级诅咒来源的即死效果。从视觉上，这些目标被赤蛮奇眼中的激光射中，从头顶被浇下一盆血，并溶解在了血中。</p><p>---------------赤蛮奇特色装备----------------<br> 理论上所有人都可以买的装备，但是好像只有赤蛮奇会用得上。</p><p>撞角 D+500<br> 可以给你的脑袋装上的撞角。装上这玩意撞人真的很疼。每一个脑袋只能装一个上去。<br> 给你的脑袋撞击增加伤害上的2附加成功。</p><p>头戴式火箭喷射器 D+500<br> 戴在脑袋后面，增加你的脑袋移速。颈椎受得了吗？<br> 给你的脑袋增加30m的移速，可以用于带着身体移动。不是赤蛮奇的角色购买使用会造成每1km2点不可避免的剧痛点数。不能和紫色蝴蝶结同时佩戴。</p><p>紫色蝴蝶结 250<br> 紫色的蝴蝶结，赤蛮奇最经典的头部装饰。你或许不能戴头盔了，但是这个还是能戴上的。<br> 为你的脑袋先攻提供2加值。当然了可以作用于你自己身上。不能和头戴式火箭喷射器同时佩戴。</p><p>-----------赤蛮奇的可升级披风系列-------------</p><p>赤红色披风tab-7.0<br> 价格：50<br> 搭载猎〇座3110芯片，穿上你就是最初代赤蛮奇啦。<br> 其实属性和防弹衣完全一样。但是特殊的，本披风占据衣物位与盔甲位。<br> 提供2/2盔甲防御和防弹属性。<br> 必须逐级购买更高级的披风。</p><p>赤红色披风note-10.1<br> 价格： D+500<br> 搭载猎〇座4412芯片，穿上你就是更强的赤蛮奇。<br> 占据盔甲位与衣物位<br> 5/5盔甲防御，防弹、防能量和提供1生命上限。<br> 接下来你必须在魔理沙特防披风，灵梦特防披风与咲夜特防披风三条特化路线中选择一条强化。选择后不可更改。</p><p>----雾雨魔理沙特防披风----</p><p>黑白耗子特防披风s-8.4<br> 价格：C+1000<br> 搭载猎〇座5420芯片，穿上你就是幻想乡最强的赤蛮奇（RAM=3G限定）。专门用来防御魔理沙的魔炮，使用对相关方面进行了特化的披风。<br> 占据盔甲位与衣物位<br> 提供8/8盔甲防御，防弹、防能量，提供1生命上限和6dr/金子。只能购买更高级的魔理沙特防披风。</p><p>黑白耗子特防披风s7+<br> 价格： B+2000<br> 搭载〇通骁龙865+(〇星特供版）芯片，穿上你就是2018年最靓赤蛮奇，附赠别在头上的紫色的spen。<br> 在防御魔理沙方面进行了特化的披风，单纯追求火力的恐怖家伙只能通过单纯追求防御来抵抗。<br> 占据盔甲位与衣物位<br> 提供15/15盔甲防御，防弹，防能量，提供1生命上限和10dr/金子。只能购买更高级的魔理沙特防披风。<br> 这件披风大到足以为你当下四面八方的攻击。这件披风获得【封闭5】。</p><p>----博丽灵梦特防披风----</p><p>赤色杀人魔特防披风tab A<br> 价格：C+1000<br> 搭载〇通骁龙410芯片，穿上你就是幻想乡最强的赤蛮奇（骁龙限定）。专门用来防御博丽灵梦的阴阳玉的披风，毕竟上次被揍得老惨了。<br> 占据盔甲位与衣物位<br> 提供10/10盔甲防御，防弹、防能量和1生命上限。<br> 披风代表着无头骑士坚韧的品行。披风为你带来基于盔甲防御的【坚韧】与【适应】特性。只能购买更高级的博丽灵梦特防披风。</p><p>赤色杀人魔特防披风tab A Spen<br> 价格：B+2000<br> 搭载猎〇座7904芯片，穿上你就是幻想乡最强的赤蛮奇,附赠别在头上的紫色的spen。专门用来防御博丽灵梦的阴阳玉的披风，毕竟上次被揍得老惨了。<br> 占据盔甲位与衣物位<br> 提供15/15盔甲防御，防弹、防能量和1生命上限。<br> 披风代表着无头骑士坚韧的品行。披风为你带来【坚韧】与【适应】特性。<br> 城管巫女飞的速度给你留下了深刻印象。<br> 披风以你的意志带你移动，给你提升120m的速度——简直就是动力甲，而这个动力甲甚至是活的！<br> 这件披风给你提供【活体护甲6】的特性。</p><p>----十六夜咲夜特防披风----</p><p>时停女仆长特防披风galaxy-view<br> 价格：C+1000<br> 搭载猎〇座7580芯片，穿上你就是18.4寸的幻想乡最大赤蛮奇。真的很大。<br> 占据盔甲位与衣物位<br> 10/10偏斜防御，防弹、防能量和1生命上限。<br> 专门用来防御十六夜咲夜的时停飞刀的披风。女仆长的时停揍人真的很恐怖，必须得有个应对手段。<br> 披风现在为你带来免疫A级及以下的时间暂停效果以及免疫接触攻击。</p><p>赤红色披风galaxy-view2<br> 价格：B+2000<br> 搭载猎〇座7884芯片，穿上你就是17.6寸的巨大赤蛮奇。为啥升级了尺寸还变小了？<br> 占据盔甲位与衣物位<br> 15/15偏斜防御，防弹、防能量和2生命上限。<br> 专门用来防御十六夜咲夜的时停飞刀的披风。女仆长的时停揍人真的很恐怖，必须得有个应对手段。<br> 披风现在为你带来免疫A级及以下的时间暂停效果以及免疫接触攻击。<br> 特殊的，你现在可以选择支付3点妖力池/神力池上限或购买250点数的妖力电池，花费一个自由动作为披风持续供能充能，使这个披风为你免疫一次致死伤害，这一效果一影片只能生效一次。这是一个B级命运来源的无敌效果。<br> 你可以以每一点上限100点数的价格购回被你消耗掉的妖力池/神力池上限，但是不能超过原本的上限。<br> 披风代表着无头骑士无所阻挡的意志。<br> 披风为你带来等同于基础移动速度固体物质穿行速度，以及5点遁力。</p><p>----------------赤蛮奇专属奇物------------------</p><p>来往于运河的人与妖 A+4000</p><p>Music Room<br> 　2面的主题曲。</p><p>和一面的吊儿郎当感不同，因为这一面是比较中二的妖怪，<br> 　所以稍微注重了一下这方面。</p><p>应该表现出了随着一定的节拍淡淡地前进的感觉吧。——zun</p><p>「柳之运河」<br> 这是一条临近人类村落的运河。<br> 河边种植着大量的柳树，绿色的柳枝垂在岸边，每到春日柳絮在河上飞荡。<br> 运河本身泛着绿波，河岸边有青苔野草。<br> 岸边有一条铺着砖石的道路，到了秋日飘落的却是枫叶。<br> 你获得一个与幻想乡人里边上柳之运河区域完全一样的10000立方米异世界，你可以把它具现化装在一个小玻璃球里，绕着你身体旋转。说是柳之运河区域，其实几乎能看见幻想乡全境，要是尽力往上去看看，甚至还能看见月之都。虽然景色都能看见，但是并不能离开中心10000平方米这个范围。距离中心越远，地形就越扭曲。更可惜的是，这里并没有人。脑袋们平时就住在这种地方吗，看起来真不错呢。<br> 你可以随时以一个迅捷动作启动它，将自己放逐到真正的幻想乡柳之运河区域的一个任意位置，这视为一个a级命运来源的异空间效果。同时，你在幻想乡内以迅捷动作启动它，也可以把自己传送回先前所在的位置，这视为一个a级命运来源的传送特性。你可以对你自己和任何接触它的人使用这个效果，如果是非自愿单位需要经过擒抱命中检定。常回家看看（笑）<br> 特殊的，只要你是草根妖怪的一员（拥有赤蛮奇，若鹭姬，今泉影狼血统之一，或者背景设定为赤蛮奇，若鹭姬，今泉影狼三人之一）就可以购买本物品。若鹭姬将空间内景色替换成雾之湖，而影狼将景色替换成迷途竹林，放逐后出现的地点也会相应的改变。本奇物名称也可更改为相应名称。</p><p>-----------------专属头颅-----------------------</p><p>头脑「七人将門の伝説」<br> 价格：C+1000 可重复购买6次<br> 将門に相も変らぬ人体同じく六人あり。——《俵藤太物语·下》<br> 传说平将门被斩首示众后，首级向关东飞去，途中力竭落地，因此在各地衍生了很多首塚传说。室町时代的《俵藤太物语》中记载平将门曾经配置了六名影武者保护自己。<br> 六名影武者就算在灯火下也没有影子。将门中箭死后，影武者们瞬间消失了。<br> 你可以向主神购买头颅位来增加你的头颅数量。包括你原本的头颅在内，你最高只能拥有七个头。<br> 头颅不占用手来持有，但依旧视为被你持有，它可以盘旋在你身边。当你死亡后，头颅们将不再受到你的意识操控的在影片中游荡。<br> 每轮一次，你可以以自由动作指挥头颅们攻击1次，武器本身具有预设特性，DP固定为34DP+4附加，你在攻击时可以如常使用头颅作为武器进行攻击，此时不以你的数值检定，依旧享受本轮武器自动预设攻击的好处。<br> 武器自动攻击需转换为独立单位模式，此时如常被范围伤害波及。<br> 这些脑袋们长得都一样，你不能改变她们的外貌。<br> 赤蛮奇脑袋<br> 体积：1<br> 力6/敏6/耐4<br> 感4/决4/智2<br> 风2/操2/沉2<br> 武技5级-武技：头 5级<br> 运动5级-投掷5级<br> 学识3级-神秘学3级<br> 调查3级-侦查3级<br> 运动3级-强韧3级<br> 其他技能1级。<br> 结构值：14<br> 移动速度：50米<br> 基础防御：4<br> 活武器：可以购买技艺与称号下的内在强化。除自己本身以外无法使用除了奇物以外的的装备，但允许附魔或改造，自身享受相关加值。<br> 杀意感知：为持有者提供料敌先机2级专长。<br> 头颅们拥有普通飞行能力。<br> 本武器具有完整的行动轮，但只能进行基础规则允许的行为与预设攻击模式，也可以正常采用它自己的属性进行攻击（基准6属性+5技能+5专业+1辅助攻击专业+武器伤害），当被攻击清空结构值时你可以支付妖力池所有妖力，使其在第二日于你手中出现。若你尚未开启妖力池，其将暂时消失直到你开启妖力池。</p><p>头脑「将門の影武者の伝説」<br> 价格：B+2000<br> 在与《俵藤太物语》同时期著成的《师门物语》中，记载的是八名影武者。赤蛮奇最多可以拥有九颗头。<br> 你可以再向主神购买开放本特殊头颅的权力。特殊头颅不能用于攻击。<br> 你获取任意无头尸体后可以用其做崇，将尸体与你的特殊头颅结合。<br> 当你死亡时，若与特殊头颅结合的尸体在你的敏感范围内，你的意识将转移到一个作祟的尸体上，作祟的尸体不需要进食、呼吸、休息，但只能进行简单的移动。<br> 作祟的尸体具有60点结构值，仅具有基础防御，移动速度为50米/轮。<br> 当你在作祟的尸体上花费7日时间适应后才可恢复为正常状态。作祟的尸体回到主神空间会立即复活。这是一个B级别、附身来源的复活效果。<br> 你最高同时拥有两颗特殊头颅<br> 这视为一个你当前血统等级来源的复活效果。你仍需要额外的1000分去购买特殊头颅，购买本技能并不赠送。</p><p>赤蛮奇的备用脑袋<br> 价格：1000<br> 用于施展头脑「将門の影武者の伝説」的脑袋备份，只能同时拥有两颗。每一颗一千块钱，用完还得重新买哦。传输速率比想象中的慢得多。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',45)])])}const C=p(n,[["render",o]]);export{m as __pageData,C as default};
